//# Pipeline Merge (Round-Robin Arbitration)

// Takes in multiple input ready/valid handshakes with associated data, and
// merges them one at a time into a single output ready/valid handshake. The
// inputs are merged in round-robin order, with equal priority, and one dead
// cycle when arbitrating to a different input.

//## Atomicity

// So long as an input holds its valid signal high (implying a continous
// stream of data), it will hold the output (once granted) and so all that
// input's data will be passed atomically, without other data interleaved in
// it. Backpressure still works via the ready signal. If the source connected
// to the input cannot provide its block of data in a single continously valid
// stream, then any other input source may grab the output in the meantime.
// Thus, if you can't avoid interleaving, attach some metadata in parallel to
// the data (e.g.: a source ID number) to allow sorting it out further down
// the pipeline.

// The IMPLEMENTATION parameter defaults to "AND", and controls the
// implementation of the Annullers inside the mux/demux. It is unlikely you
// will need to change it.

//## Avoiding combinational loops

// As a design convention, we must avoid a combinational path between the
// valid and ready signals in a given pipeline interface, because if the other
// end of the pipeline connection also has a ready/valid combinational path,
// connecting these two interfaces will form a combinational loop, which
// cannot be analyzed for timing, or simulated reliably.

// Thus, the input interfaces here are buffered to break the combinational
// path, even if the buffering is redundant. It's not worth the risk of a bad
// simulation or synthesis otherwise.

`default_nettype none

module Pipeline_Merge_Round_Robin
#(
    parameter WORD_WIDTH     = 0,
    parameter INPUT_COUNT    = 0,
    parameter IMPLEMENTATION = "AND",

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH   = WORD_WIDTH * INPUT_COUNT
)
(
    input  wire                     clock,
    input  wire                     clear,

    input  wire [INPUT_COUNT-1:0]   input_valid,
    output wire [INPUT_COUNT-1:0]   input_ready,
    input  wire [TOTAL_WIDTH-1:0]   input_data,

    output reg                      output_valid,
    input  wire                     output_ready,
    output wire [WORD_WIDTH-1:0]    output_data
);

    localparam INPUT_ZERO = {INPUT_COUNT{1'b0}};

    initial begin
        output_valid = 1'b0;
    end

// First, we must buffer the input interfaces to break the combinational path
// from valid to ready.

    wire [INPUT_COUNT-1:0]   input_valid_buffered;
    wire [INPUT_COUNT-1:0]   input_ready_buffered;
    wire [TOTAL_WIDTH-1:0]   input_data_buffered;

    generate
        genvar j;
        for(j=0; j < INPUT_COUNT; j=j+1) begin: per_input
            Pipeline_Skid_Buffer
            #(
                .WORD_WIDTH (WORD_WIDTH)
            )
            input_buffer
            (
                .clock          (clock),
                .clear          (clear),

                .input_valid    (input_valid[j]),
                .input_ready    (input_ready[j]),
                .input_data     (input_data [WORD_WIDTH*j +: WORD_WIDTH]),

                .output_valid   (input_valid_buffered[j]),
                .output_ready   (input_ready_buffered[j]),
                .output_data    (input_data_buffered [WORD_WIDTH*j +: WORD_WIDTH])
            );
        end
    endgenerate

// Then filter the input valid signals to only one, in round-robin order.

    wire [INPUT_COUNT-1:0] input_valid_granted;

    Arbiter_Round_Robin
    #(
        .INPUT_COUNT (INPUT_COUNT)
    )
    pipeline_arbiter
    (
        .clock      (clock),
        .clear      (clear),
        .requests   (input_valid_buffered),
        .grant      (input_valid_granted)
    );

// It takes one cycle for the Round_Robin_Arbiter to change state, so mask the
// granted valid input with the original valid input so that when the original
// valid input goes low, we don't leave the granted valid input high for one
// extra cycle, which would cause one extra, incorrect data transfer.

    reg [INPUT_COUNT-1:0] input_valid_granted_masked = INPUT_ZERO;

    always @(*) begin
        input_valid_granted_masked = input_valid_buffered & input_valid_granted;
    end

// If any arbitrated input valid is set, then pass it to the output valid port.

    always @(*) begin
        output_valid = (input_valid_granted_masked != INPUT_ZERO);
    end

// Then use the filtered valid signal to select the data to pass to the
// output.

    Multiplexer_One_Hot
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .WORD_COUNT     (INPUT_COUNT),
        .OPERATION      ("OR"),
        .IMPLEMENTATION (IMPLEMENTATION)
    )
    data_out_mux
    (
        .selectors      (input_valid_granted_masked),
        .words_in       (input_data_buffered),
        .word_out       (output_data)
    );

// Use the filtered valid signal to steer the selected output ready port to
// the input ready port. Since this is a single-bit signal, the valid isn't
// necessary if we don't broadcast.

    Demultiplexer_One_Hot
    #(
        .BROADCAST      (0),
        .WORD_WIDTH     (1),
        .OUTPUT_COUNT   (INPUT_COUNT),
        .IMPLEMENTATION (IMPLEMENTATION)
    )
    ready_in_demux
    (
        .selectors      (input_valid_granted_masked),
        .word_in        (output_ready),
        .words_out      (input_ready_buffered),
        // verilator lint_off PINCONNECTEMPTY
        .valids_out     ()
        // verilator lint_on  PINCONNECTEMPTY
    );

endmodule

//# Pipeline Merge (Priority Arbitration)

// Takes in multiple input ready/valid handshakes with associated data, and
// merges them one at a time into a single output ready/valid handshake. The
// inputs are merged by priority, with the lowest indexed input having
// the highest priority.

//## Arbitration

// So long as an input has the highest priority (lowest bit) valid signal
// asserted and is granted its turn, it's data will be passed to the output.
// Once valid is released, the turn is lost if a higher priority valid is
// asserted. Backpressure still works via the corresponding ready signal.

// The IMPLEMENTATION parameter defaults to "AND", and controls the
// implementation of the Annullers inside the mux/demux. It is unlikely you
// will need to change it.

//## Avoiding combinational loops

// As a design convention, we must avoid a combinational path between the
// valid and ready signals in a given pipeline interface, because if the other
// end of the pipeline connection also has a ready/valid combinational path,
// connecting these two interfaces will form a combinational loop, which
// cannot be analyzed for timing, or simulated reliably.

// Thus, the input interfaces here are buffered to break the combinational
// path, even if the buffering is redundant. It's not worth the risk of a bad
// simulation or synthesis otherwise.

`default_nettype none

module Pipeline_Merge_Priority
#(
    parameter WORD_WIDTH     = 0,
    parameter INPUT_COUNT    = 0,
    parameter IMPLEMENTATION = "AND",

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH   = WORD_WIDTH * INPUT_COUNT
)
(
    input  wire                     clock,
    input  wire                     clear,

    input  wire [INPUT_COUNT-1:0]   input_valid,
    output wire [INPUT_COUNT-1:0]   input_ready,
    input  wire [TOTAL_WIDTH-1:0]   input_data,

    output reg                      output_valid,
    input  wire                     output_ready,
    output wire [WORD_WIDTH-1:0]    output_data
);

    localparam INPUT_ZERO = {INPUT_COUNT{1'b0}};
    localparam INPUT_ONES = {INPUT_COUNT{1'b1}};

    initial begin
        output_valid = 1'b0;
    end

// First, we must buffer the input interfaces to break the combinational path
// from valid to ready.

    wire [INPUT_COUNT-1:0]   input_valid_buffered;
    wire [INPUT_COUNT-1:0]   input_ready_buffered;
    wire [TOTAL_WIDTH-1:0]   input_data_buffered;

    generate
        genvar j;
        for(j=0; j < INPUT_COUNT; j=j+1) begin: per_input
            Pipeline_Skid_Buffer
            #(
                .WORD_WIDTH      (WORD_WIDTH),
                .CIRCULAR_BUFFER (0)            // Not meaningful here
            )
            input_buffer
            (
                .clock          (clock),
                .clear          (clear),

                .input_valid    (input_valid[j]),
                .input_ready    (input_ready[j]),
                .input_data     (input_data [WORD_WIDTH*j +: WORD_WIDTH]),

                .output_valid   (input_valid_buffered[j]),
                .output_ready   (input_ready_buffered[j]),
                .output_data    (input_data_buffered [WORD_WIDTH*j +: WORD_WIDTH])
            );
        end
    endgenerate

// If any input is valid, then pass it to the output valid port.

    always @(*) begin
        output_valid = (input_valid_buffered != INPUT_ZERO);
    end

// Then filter the input valid signals to only one, in order of priority.
// Least-significant valid bit has highest priority and holds the grant until
// valid is released.

    wire [INPUT_COUNT-1:0] input_valid_granted;

    Arbiter_Priority
    #(
        .INPUT_COUNT    (INPUT_COUNT)
    )
    pipeline_arbiter
    (
        .clock          (clock),
        .clear          (clear),
        .requests       (input_valid_buffered),
        .requests_mask  (INPUT_ONES),
        // verilator lint_off PINCONNECTEMPTY
        .grant_previous (),
        // verilator lint_on  PINCONNECTEMPTY
        .grant          (input_valid_granted)
    );

// Then use the filtered valid signal to select the data to pass to the
// output.

    Multiplexer_One_Hot
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .WORD_COUNT     (INPUT_COUNT),
        .OPERATION      ("OR"),
        .IMPLEMENTATION (IMPLEMENTATION)
    )
    data_out_mux
    (
        .selectors      (input_valid_granted),
        .words_in       (input_data_buffered),
        .word_out       (output_data)
    );

// Use the filtered valid signal to steer the selected output ready port to
// the input ready port. Since this is a single-bit signal, the valid isn't
// necessary if we don't broadcast.

    Demultiplexer_One_Hot
    #(
        .BROADCAST      (0),
        .WORD_WIDTH     (1),
        .OUTPUT_COUNT   (INPUT_COUNT),
        .IMPLEMENTATION (IMPLEMENTATION)
    )
    ready_in_demux
    (
        .selectors      (input_valid_granted),
        .word_in        (output_ready),
        .words_out      (input_ready_buffered),
        // verilator lint_off PINCONNECTEMPTY
        .valids_out     ()
        // verilator lint_on  PINCONNECTEMPTY
    );

endmodule

//# Pipeline Gate

// Conditionally blocks ready/valid handshakes and data from passing through
// a pipeline. Handshakes complete only when the `enable` input is high.
// There is no buffering: this is purely combinational. The `enable` input
// MUST be changed synchronously to the clock.

// It is not enough to block only valid or ready: if valid is blocked, then
// the sender can still see the receiver's ready and complete a handshake,
// dropping that data. The opposite happens when blocking only ready, with the
// receiver taking in stale data or garbage.

// An example use case for a gate is to prevent a FIFO from sending out data
// while you are loading it with some unit composed of many words (e.g.
// a packet). 

//## Configuration

// If the `GATE_DATA` parameter is non-zero, a disabled gate will not let any
// data through and zero it out.  Else the data is always a simple
// pass-through, and only the ready/valid handshakes are gated. Change the
// [Annuller](./Annuller.html) `IMPLEMENTATION` as necessary, but the default
// should be fine.

`default_nettype none

module Pipeline_Gate
#(
    parameter WORD_WIDTH        = 0,
    parameter IMPLEMENTATION    = "AND",
    parameter GATE_DATA         = 0
)
(
    input   wire                        enable,

    output  wire                        input_ready,
    input   wire                        input_valid,
    input   wire    [WORD_WIDTH-1:0]    input_data,

    output  wire                        output_valid,
    input   wire                        output_ready,
    output  wire    [WORD_WIDTH-1:0]    output_data
);

    generate

        if (GATE_DATA != 0) begin : gen_gate_data

            Annuller
            #(
                .WORD_WIDTH     (WORD_WIDTH + 1 + 1),
                .IMPLEMENTATION (IMPLEMENTATION)
            )
            gate_control_and_data
            (
                .annul      (enable == 1'b0),
                .data_in    ({input_data,  output_ready, input_valid}),
                .data_out   ({output_data, input_ready,  output_valid})
            );

        end
        else begin : gen_pass_data

            assign output_data = input_data;

            Annuller
            #(
                .WORD_WIDTH     (1 + 1),
                .IMPLEMENTATION (IMPLEMENTATION)
            )
            gate_control_only
            (
                .annul      (enable == 1'b0),
                .data_in    ({output_ready, input_valid}),
                .data_out   ({input_ready,  output_valid})
            );

        end

    endgenerate

endmodule

//# Pipeline Credit Gate

// Gates a pipeline if the internal credit count is zero. A separate pulse
// input adds one credit per pulse. Continuous, multi-cycles pulses are allowed.
// Each completed pipeline handshake from input to output consumes one credit.  The credit count
// is available to drive other logic (usually another [Pipeline Gate](./Pipeline_Gate.html)).

// The maximum number of credits is set by `MAX_CREDIT_COUNT` and will
// saturate at that value if attempting to add more credits. Saturating the
// credit count will pulse `current_credit_count_max` on the next cycle when
// `current_credit_count` updates, and trying to add credits past the limit
// will pulse `add_credit_fail` on the next cycle.

`default_nettype none

module Pipeline_Credit_Gate
#(
    parameter WORD_WIDTH        = 0,
    parameter MAX_CREDIT_COUNT  = 0,

    // Do not set at instantiation, except in Vivado IPI.
    parameter CREDIT_WIDTH      = clog2(MAX_CREDIT_COUNT) + 1 // +1 to hold powers of two exactly
)
(
    input   wire                        clock,
    input   wire                        clear,

    input   wire                        input_data_valid,
    output  wire                        input_data_ready,
    input   wire    [WORD_WIDTH-1:0]    input_data,

    input   wire                        add_credit_pulse,
    output  wire                        add_credit_fail,
    output  wire    [CREDIT_WIDTH-1:0]  current_credit_count,
    output  wire                        current_credit_count_max,
    output  wire                        current_credit_count_zero,

    output  wire                        output_data_valid,
    input   wire                        output_data_ready,
    output  wire    [WORD_WIDTH-1:0]    output_data
);

    `include "clog2_function.vh"

    localparam CREDIT_ZERO = {CREDIT_WIDTH{1'b0}};
    localparam CREDIT_ONE  = {{CREDIT_WIDTH-1{1'b0}},1'b1};

// Obviously, we need a Pipeline Gate at the heart of this module.

    reg open_gate = 1'b0;

    always @(*) begin
        open_gate = (current_credit_count_zero == 1'b0);
    end

    Pipeline_Gate
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .IMPLEMENTATION ("AND"),
        .GATE_DATA      (0)
    )
    pipeline_gate
    (
        .enable         (open_gate),

        .input_ready    (input_data_ready),
        .input_valid    (input_data_valid),
        .input_data     (input_data),

        .output_valid   (output_data_valid),
        .output_ready   (output_data_ready),
        .output_data    (output_data)
    );

// And a way to count credits and saturate at the max count.

// We cannot add pipe stages to the accumulator, else the adding/consuming of
// credits takes multiple cycles and that both requires more pipeline logic,
// and divides the througput by the number of pipe stages!

    reg credit_incr_decr        = 1'b0;
    reg credit_incr_decr_valid  = 1'b0;

    Accumulator_Binary_Saturating
    #(
        .EXTRA_PIPE_STAGES  (0), // DO NOT CHANGE. MUST BE 0 OR WILL NOT OPERATE PROPERLY (NO HANDLING OF "DONE" LATENCY)
        .WORD_WIDTH         (CREDIT_WIDTH),
        .INITIAL_VALUE      (CREDIT_ZERO)
    )
    credit_counter
    (
        .clock                              (clock),
        .clock_enable                       (1'b1),

        .clear                              (clear),
        // verilator lint_off PINCONNECTEMPTY
        .clear_done                         (),
        // verilator lint_on  PINCONNECTEMPTY

        .increment_carry_in                 (1'b0),
        .increment_add_sub                  (credit_incr_decr), // 0/1 --> +/-
        .increment_value                    (CREDIT_ONE),
        .increment_valid                    (credit_incr_decr_valid),
        // verilator lint_off PINCONNECTEMPTY
        .increment_done                     (),
        // verilator lint_on  PINCONNECTEMPTY

        .load_value                         (CREDIT_ZERO),
        .load_valid                         (1'b0),
        // verilator lint_off PINCONNECTEMPTY
        .load_done                          (),
        // verilator lint_on  PINCONNECTEMPTY

        .limit_max                          (MAX_CREDIT_COUNT [CREDIT_WIDTH-1:0]),
        .limit_min                          (CREDIT_ZERO),

        // verilator lint_off PINCONNECTEMPTY
        .accumulated_value                  (current_credit_count),
        .accumulated_value_carry_out        (),
        .accumulated_value_carries          (),
        .accumulated_value_at_limit_max     (current_credit_count_max),
        .accumulated_value_over_limit_max   (add_credit_fail),
        .accumulated_value_at_limit_min     (current_credit_count_zero),
        .accumulated_value_under_limit_min  ()
        // verilator lint_on  PINCONNECTEMPTY
    );

// Finally, the control logic. We can simply track the input handshake since
// the Pipeline Gate is unbuffered (combinational).

    localparam CREDIT_INCREMENT = 1'b0;
    localparam CREDIT_DECREMENT = 1'b1;

    reg handshake_done = 1'b0;

    always @(*) begin
        handshake_done          = (input_data_ready == 1'b1) && (input_data_valid == 1'b1);
        credit_incr_decr        = (handshake_done   == 1'b1) ? CREDIT_DECREMENT : CREDIT_INCREMENT;
        credit_incr_decr        = (add_credit_pulse == 1'b1) ? CREDIT_INCREMENT : credit_incr_decr;
        credit_incr_decr_valid  = (handshake_done != add_credit_pulse);
    end

endmodule

//# Annuller (Both Kinds)

// Takes in a word-wide signal, and passes it through, unless `annul` is high,
// then the signal is gated to zero.  We put something this simple into
// a module since it conveys design intent (e.g.: "turn this opcode into
// a no-op"), and avoids an RTL schematic cluttered with a bunch of gates.

// Annulling shows up in many designs: instead of using a multiplexer, we can
// selectively annul all but one input and OR-reduce to a result, which uses
// the final LUTs more efficiently. 
// While this is how a multiplexer works internally, breaking it open like
// this allows us to control the pipelining directly (which is relevant if you
// are going to have a lot of inputs), and allows us to select alternative
// conflict resolutions if two or more inputs remain after annulling:

// * reduce them to a single result using AND/OR/XOR,
// * feed them to an arbiter so you can process each remaining input in sequence,
// * have multiple final stages do different things in parallel with the remaining inputs.

// Essentially, Annulling allows us to easily think about calculating multiple
// things in parallel and keeping only the results we want. However, throwing
// away work increases performance at the expense of efficiency. Try to use
// the lost information if you can.

//## Implementation Options

// Some experimentation by others has shown that CAD tools will pattern-match
// on the description of the gating operation, resulting in different
// synth results depending on whether you describe the signal gating using
// a multiplexer or an AND gate. The synthesized logic may end up using the
// reset/clear pin of a flip-flop, or may create AND-gate logic after the
// flip-flop, which then gets folded into other LUT logic. Thus, both
// implementation are available via the `IMPLEMENTATION` parameter.

// The Annuller implementation does not generally matter. However, on FPGAs, the
// reset/clear signal is common to all flip-flops in a group (*known as a CLB
// (Common Logic Block) for Xilinx, or a LAB (Logic Array block) for Intel*).
// Thus, flip-flops driven by different reset/clear logic cannot be packed
// together, though since an Annuller applies the same reset/clear logic to
// all signals, they should pack normally.

// Register retiming may also be affected, again due to the reset/clear
// signals, but again, this is a minor problem if one at all. Assume things
// are fine, and check your synthesis results if a bottleneck appears.

`default_nettype none

module Annuller
#(
    parameter       WORD_WIDTH          = 0,
    parameter       IMPLEMENTATION      = ""
)
(
    input   wire                        annul,
    input   wire    [WORD_WIDTH-1:0]    data_in,
    output  reg     [WORD_WIDTH-1:0]    data_out
);

    localparam ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        data_out = ZERO;
    end

    generate
        if (IMPLEMENTATION == "MUX") begin : gen_mux
            always @(*) begin
                data_out = (annul == 1'b0) ? data_in : ZERO;
            end
        end
        else
        if (IMPLEMENTATION == "AND") begin : gen_and
            always @(*) begin
                data_out = data_in & {WORD_WIDTH{annul == 1'b0}};
            end
        end
    endgenerate

endmodule

//# Signed Binary Accumulator, with Saturation

// Adds/subtracts the signed `increment_value` to the signed
// `accumulated_value` when `increment_valid` is pulsed high *for one cycle*.
// A new increment may be added when `increment_done` pulses high, in the same
// cycle if necessary. 

// Pulsing `load_valid` high for one cycle replaces the `accumulated_value`
// with the `load_value`. A new load can be done when `load_done` pulses high,
// in the same cycle if necessary.

// Pulsing `clear` high for one cycle puts the accumulator back at
// `INITIAL_VALUE`. The accumulator can be cleared again once `clear_done`
// pulses high, in the same cycle if necessary.

// Deasserting `clock_enable` freezes the accumulator: new increments, loads,
// and clears are ignored, the internal pipeline (if any) holds steady, and
// all outputs remain static.

// When chaining accumulators, which may happen if you are incrementing in
// unusual bases where each digit has its own accumulator, AND the
// `accumulated_value_carry_out` of the previous accumulator with the signal
// fed to the `increment_valid` input of the next accumulator. The
// `increment_carry_in` is kept for generality.

//## Saturation

// If the increment **or the load** would cause the accumulator to go past the
// signed minimum or maximum limits, the accumulator will saturate at the
// nearest limit value and also raise one or more of the min/max limit signals
// until the next operation. **The maximum limit must be greater or equal than
// the minimum limit.** If the limits are reversed, such that limit_max
// < limit_min, the result will be meaningless.

//## Pipelining and Concurrency

// This module is pipelined since we are chaining adder/subtractors together
// inside the
// [Adder_Subtractor_Binary_Saturating](./Adder_Subtractor_Binary_Saturating.html)
// module, so the total carry-chain is twice as long as expected, plus 2 more
// bits to avoid overflow. Most of the time, this will take longer than your
// clock cycle since the carry-chain of arithmetic logic is often a limiting
// factor in timing closure.

// We can't retime a pipeline from outside since there is a loop, so we
// pipeline inside the loop here, and let that retime across the carry-chains.
// The price to pay is a latency of EXTRA_PIPE_STAGES+1 cycles between an
// increment, load, or clear, and the corresponding "done" signal.  This
// latency is why the input pulses must be asserted *for only one cycle* when
// `EXTRA_PIPE_STAGES` is greater than zero, then wait until the command has
// completed before pulsing again, else any latter increments or loads will
// override the previous ones (since the accumulated_value will have not yet
// updated).

`default_nettype none

module Accumulator_Binary_Saturating
#(
    parameter                   EXTRA_PIPE_STAGES   = -1,
    parameter                   WORD_WIDTH          =  0,
    parameter [WORD_WIDTH-1:0]  INITIAL_VALUE       =  0
)
(
    input   wire                        clock,
    input   wire                        clock_enable,

    input   wire                        clear,
    output  wire                        clear_done,

    input   wire                        increment_carry_in,
    input   wire                        increment_add_sub,  // 0/1 --> +/-
    input   wire    [WORD_WIDTH-1:0]    increment_value,
    input   wire                        increment_valid,
    output  wire                        increment_done,

    input   wire    [WORD_WIDTH-1:0]    load_value,
    input   wire                        load_valid,
    output  wire                        load_done,

    input   wire    [WORD_WIDTH-1:0]    limit_max,
    input   wire    [WORD_WIDTH-1:0]    limit_min,

    output  wire    [WORD_WIDTH-1:0]    accumulated_value,
    output  wire                        accumulated_value_carry_out,
    output  wire    [WORD_WIDTH-1:0]    accumulated_value_carries,
    output  wire                        accumulated_value_at_limit_max,
    output  wire                        accumulated_value_over_limit_max,
    output  wire                        accumulated_value_at_limit_min,
    output  wire                        accumulated_value_under_limit_min
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

// Here, we pipeline the inputs so that all signals further down are in sync,
// and to place the register pipeline inside the loop formed by the
// Adder_Subtractor_Binary_Saturating and the output register, so we can have
// forward retiming move it into the Adder_Subtractor_Binary_Saturating logic.
// (Backwards retiming is more difficult, and not supported by Vivado
// post-synth optimizations)

    wire                    clear_pipelined;

    wire                    increment_carry_in_pipelined;
    wire                    increment_add_sub_pipelined;
    wire [WORD_WIDTH-1:0]   increment_value_pipelined;
    wire                    increment_valid_pipelined;

    wire [WORD_WIDTH-1:0]   load_value_pipelined;
    wire                    load_valid_pipelined;

    wire [WORD_WIDTH-1:0]   limit_max_pipelined;
    wire [WORD_WIDTH-1:0]   limit_min_pipelined;

    wire [WORD_WIDTH-1:0]   accumulated_value_pipelined;

    generate
        if (EXTRA_PIPE_STAGES == 0) begin : gen_no_pipe
            assign clear_pipelined              = clear;
            assign increment_carry_in_pipelined = increment_carry_in;
            assign increment_add_sub_pipelined  = increment_add_sub;
            assign increment_value_pipelined    = increment_value;
            assign increment_valid_pipelined    = increment_valid;
            assign load_value_pipelined         = load_value;
            assign load_valid_pipelined         = load_valid;
            assign limit_max_pipelined          = limit_max;
            assign limit_min_pipelined          = limit_min;
            assign increment_carry_in_pipelined = increment_carry_in;
            assign accumulated_value_pipelined  = accumulated_value;
        end
        else if (EXTRA_PIPE_STAGES > 0) begin: gen_extra_pipe

            localparam PIPELINE_WIDTH       = (WORD_WIDTH * 5) + 5;
            localparam PIPELINE_WORD_ZERO   = {PIPELINE_WIDTH{1'b0}};
            localparam PIPELINE_ZERO        = {EXTRA_PIPE_STAGES{PIPELINE_WORD_ZERO}};

            Register_Pipeline
            #(
                .WORD_WIDTH     (PIPELINE_WIDTH),
                .PIPE_DEPTH     (EXTRA_PIPE_STAGES),
                // concatenation of each stage initial/reset value
                .RESET_VALUES   (PIPELINE_ZERO)
            )
            accumulator_pipeline
            (
                .clock          (clock),
                .clock_enable   (clock_enable),
                .clear          (1'b0),
                .parallel_load  (1'b0),
                .parallel_in    (PIPELINE_ZERO),
                // verilator lint_off PINCONNECTEMPTY
                .parallel_out   (),
                // verilator lint_on  PINCONNECTEMPTY
                .pipe_in        ({limit_max,           limit_min,           increment_valid,           increment_value,           load_valid,           load_value,           increment_add_sub,           increment_carry_in,           accumulated_value,           clear}),
                .pipe_out       ({limit_max_pipelined, limit_min_pipelined, increment_valid_pipelined, increment_value_pipelined, load_valid_pipelined, load_value_pipelined, increment_add_sub_pipelined, increment_carry_in_pipelined, accumulated_value_pipelined, clear_pipelined})
            );
        end
    endgenerate

// 
// **After this point, only use the pipelined inputs.**
//

// If we are *loading* then substitute the `accumulated_value` and `carry_in` with
// zero, and the `increment` with the `load_value`. 
// If we are *clearing* then substitute the `accumulated_value` and `carry_in` with
// zero, and the `increment` with the `INITIAL_VALUE`. 
// Converting a load or clear to an addition to zero prevents us from loading
// a value outside the given limits, which could really upset things in the
// enclosing logic, and will set the output status bits correctly.

    reg gate_accumulated_value = 1'b0;

    always @(*) begin
        gate_accumulated_value = (load_valid_pipelined == 1'b1) || (clear_pipelined == 1'b1);
    end

    wire [WORD_WIDTH-1:0] accumulated_value_gated;
    wire                  increment_carry_in_gated;

    Annuller
    #(
        .WORD_WIDTH     (WORD_WIDTH + 1),
        .IMPLEMENTATION ("AND")
    )
    gate_accumulated
    (
        .annul          (gate_accumulated_value == 1'b1),
        .data_in        ({accumulated_value_pipelined, increment_carry_in_pipelined}),
        .data_out       ({accumulated_value_gated,     increment_carry_in_gated})
    );

    reg [WORD_WIDTH-1:0] increment_selected = WORD_ZERO;

    always @(*) begin
        increment_selected = (load_valid_pipelined == 1'b1) ? load_value_pipelined : increment_value_pipelined;
        increment_selected = (clear_pipelined      == 1'b1) ? INITIAL_VALUE        : increment_selected;
    end

// Apply the increment to the current accumulator value, or the load value to
// an accumulator value of zero, or the initial value to an accumulator value
// of zero, all with saturation.

    wire [WORD_WIDTH-1:0]   incremented_value_internal;
    wire                    accumulated_value_carry_out_internal;
    wire [WORD_WIDTH-1:0]   accumulated_value_carries_internal;
    wire                    accumulated_value_at_limit_max_internal;
    wire                    accumulated_value_over_limit_max_internal;
    wire                    accumulated_value_at_limit_min_internal;
    wire                    accumulated_value_under_limit_min_internal;

    Adder_Subtractor_Binary_Saturating
    #(
        .WORD_WIDTH     (WORD_WIDTH)
    )
    add_increment
    (
        .limit_max      (limit_max_pipelined),
        .limit_min      (limit_min_pipelined),
        .add_sub        (increment_add_sub_pipelined),  // 0/1 -> A+B/A-B
        .carry_in       (increment_carry_in_gated),
        .A              (accumulated_value_gated),
        .B              (increment_selected),
        .sum            (incremented_value_internal),
        .carry_out      (accumulated_value_carry_out_internal),
        .carries        (accumulated_value_carries_internal),
        .at_limit_max    (accumulated_value_at_limit_max_internal),
        .over_limit_max  (accumulated_value_over_limit_max_internal),
        .at_limit_min    (accumulated_value_at_limit_min_internal),
        .under_limit_min (accumulated_value_under_limit_min_internal)
    );

// Then, update the accumulator register and other outputs sychronized to
// it. Update the registers if load or increment or the clear pulse is valid. 

    reg enable_output  = 1'b0;

    always @(*) begin
        enable_output  = (increment_valid_pipelined == 1'b1) || (load_valid_pipelined == 1'b1) || (clear_pipelined == 1'b1);
        enable_output  = (enable_output             == 1'b1) && (clock_enable         == 1'b1);
    end

    Register
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .RESET_VALUE    (INITIAL_VALUE)
    )
    accumulator
    (
        .clock          (clock),
        .clock_enable   (enable_output),
        .clear          (1'b0),
        .data_in        (incremented_value_internal),
        .data_out       (accumulated_value)
    );

    Register
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .RESET_VALUE    (WORD_ZERO)
    )
    carries
    (
        .clock          (clock),
        .clock_enable   (enable_output),
        .clear          (1'b0),
        .data_in        (accumulated_value_carries_internal),
        .data_out       (accumulated_value_carries)
    );

    localparam STATUS_BITS_COUNT = 5;
    localparam STATUS_BITS_ZERO  = {STATUS_BITS_COUNT{1'b0}};

    Register
    #(
        .WORD_WIDTH     (STATUS_BITS_COUNT),
        .RESET_VALUE    (STATUS_BITS_ZERO)
    )
    status_bits
    (
        .clock          (clock),
        .clock_enable   (enable_output),
        .clear          (1'b0),
        .data_in        ({accumulated_value_carry_out_internal,  accumulated_value_at_limit_max_internal,  accumulated_value_over_limit_max_internal,  accumulated_value_at_limit_min_internal,  accumulated_value_under_limit_min_internal}),
        .data_out       ({accumulated_value_carry_out,           accumulated_value_at_limit_max,           accumulated_value_over_limit_max,           accumulated_value_at_limit_min,           accumulated_value_under_limit_min})
    );

// Finally, output the "done" signals, which are the pipelined command pulses
// plus one register delay to synchronize them to the updated
// `accumulated_value` and related data.

    Register
    #(
        .WORD_WIDTH     (1),
        .RESET_VALUE    (1'b0)
    )
    for_clear
    (
        .clock          (clock),
        .clock_enable   (clock_enable),
        .clear          (1'b0),
        .data_in        (clear_pipelined),
        .data_out       (clear_done)
    );

    Register
    #(
        .WORD_WIDTH     (1),
        .RESET_VALUE    (1'b0)
    )
    for_increment
    (
        .clock          (clock),
        .clock_enable   (clock_enable),
        .clear          (1'b0),
        .data_in        (increment_valid_pipelined),
        .data_out       (increment_done)
    );

    Register
    #(
        .WORD_WIDTH     (1),
        .RESET_VALUE    (1'b0)
    )
    for_load
    (
        .clock          (clock),
        .clock_enable   (clock_enable),
        .clear          (1'b0),
        .data_in        (load_valid_pipelined),
        .data_out       (load_done)
    );

endmodule

//# Multiplexer (One-Hot)

// Takes in a one-hot bit vector (`selector`), and outputs the value of the
// corresponding input. All selectors and inputs are concatenated into
// a single vector each.

// If more than one `selector` bit is set, the output is a Boolean combination
// of the selected input words, as specified by `OPERATION`: OR for a plain
// multiplexer, AND to show each bit where all the words agree, NOR to show each
// bit which are not set in all the words, etc...

// The `IMPLEMENTATION` parameter defaults to "AND" since this is all Boolean
// logic, though if you are feeding the input words from registers all sharing
// common control logic, you might get a possibly better result by selecting
// "MUX". If it matters for speed or area, use the implementation which ends
// up using the register's reset/clear pin, which will remove the Annuller
// logic from the multiplexer itself.

`default_nettype none

module Multiplexer_One_Hot
#(
    parameter       WORD_WIDTH          = 0,
    parameter       WORD_COUNT          = 0,
    parameter       OPERATION           = "OR",
    parameter       IMPLEMENTATION      = "AND",

    // Do not set at instantiation
    parameter   TOTAL_WIDTH = WORD_COUNT * WORD_WIDTH
)
(
    input   wire    [WORD_COUNT-1:0]    selectors,
    input   wire    [TOTAL_WIDTH-1:0]   words_in,
    output  wire    [WORD_WIDTH-1:0]    word_out
);

// First, create a copy of `words_in`, but with non-selected words annulled.

    wire [TOTAL_WIDTH-1:0] words_in_selected;

    generate

        genvar i;

        for (i=0; i < WORD_COUNT; i=i+1) begin : per_word

            Annuller
            #(
                .WORD_WIDTH     (WORD_WIDTH),
                .IMPLEMENTATION (IMPLEMENTATION)
            )
            select_input
            (
                .annul       (selectors[i] == 1'b0),
                .data_in     (words_in          [WORD_WIDTH*i +: WORD_WIDTH]),
                .data_out    (words_in_selected [WORD_WIDTH*i +: WORD_WIDTH])
            );

        end

//# A Priority Arbiter

// Returns a one-hot grant bitmask of the least-significant bit set in a word,
// where bit 0 can be viewed as having highest priority. *A grant is held
// until the request is released.*

// The requestors must raise and hold a `requests` bit and wait until the
// corresponding `grant` bit rises to begin their transaction. *Grants are
// calculated combinationally from the requests*, so pipeline as necessary.
// The highest priority pending and unmasked request is granted once the
// currently granted request is released.  The grant remains for as long as
// the request is held without interruption. Requesters can raise or drop
// their requests before their turn comes, but this must be done synchronously
// to the clock.

//## Usage

// A common use-case for an arbiter is to drive a [one-hot
// multiplexer](./Multiplexer_One_Hot.html) to select one of multiple senders
// requesting for one receiver, or one of multiple receivers requesting from
// one sender. This arrangement requires that the requestors can raise and
// hold a `requests` bit, wait until they receive the correspondig `grant` bit
// to begin their transaction, and to drop their `requests` bit only once they
// are done.  This is very similar to a ready/valid handshake, except that the
// transaction cannot be interrupted, else the granted access is lost.

//## Fairness

// **A Priority Arbiter is not fair:** if a higher-priority request happens too
// frequently it will starve lower-priority requests, and if a lower-priority
// request holds its grant too long it will starve higher-priority requests,
// causing priority inversion. To distribute the grants fairly, you need
// a [Round-Robin Arbiter](./Arbiter_Round_Robin.html).

//### Customizations

// To enable the creation of custom fairness adjustments, the `requests_mask`
// input can be used to exclude one or more requests from being granted in the
// current cycle, and must be updated synchronously to the `clock`. The
// `requests_mask` is arbitrary, and if desired can be calculated from the
// current `requests`, the `grant_previous` one-hot output which holds the
// `grant` from the previous clock cycle, and the current one-hot `grant`
// output.

// * Since a grant typically lasts longer than one cycle and won't get granted
// again for several cycles, taking multiple cycles to compute the next
// `requests_mask` is a valid option.
// * The `requests_mask` is applied combinationally to the `requests` input
// and to the internal `grant_previous`, both of which have a combinational
// path to `grant`, so pipeline as necessary. 

// If unused, leave `requests_mask` set to all-ones, and the masking logic
// will optimize away.

`default_nettype none

module Arbiter_Priority
#(
    parameter INPUT_COUNT = 0
)
(
    input   wire                        clock,
    input   wire                        clear,

    input   wire    [INPUT_COUNT-1:0]   requests,
    input   wire    [INPUT_COUNT-1:0]   requests_mask,  // Set to all-ones if unused.
    output  wire    [INPUT_COUNT-1:0]   grant_previous,
    output  reg     [INPUT_COUNT-1:0]   grant
);

    localparam INPUT_ZERO = {INPUT_COUNT{1'b0}};

    initial begin
        grant = INPUT_ZERO;
    end

// First we filter the requests, masking off any externally disabled requestst
// (`requests_mask` bit is 0)

    reg  [INPUT_COUNT-1:0] requests_masked = INPUT_ZERO;

    always @(*) begin
        requests_masked = requests & requests_mask;
    end

// Then, from the remaining requests, we further mask out all but the highest
// priority (lowest bit) set request. This is the new grant candidate.

    wire [INPUT_COUNT-1:0] grant_candidate;
    Bitmask_Isolate_Rightmost_1_Bit
    #(
        .WORD_WIDTH (INPUT_COUNT)
    )
    priority_mask
    (
        .word_in    (requests_masked),
        .word_out   (grant_candidate)
    );

// If the request granted on the previous clock cycle is still active, hold it.
// Else, select the current candidate.   

    always @(*) begin
        grant = ((requests & grant_previous) != INPUT_ZERO) ? grant_previous : grant_candidate;
    end

// A grant cannot be interrupted by a higher priority request until the current 
// granted request is released. We need a register to store the current grant 
// for the next clock cycle.

    Register
    #(
        .WORD_WIDTH     (INPUT_COUNT),
        .RESET_VALUE    (INPUT_ZERO)
    )
    previously_granted_request
    (
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (clear),
        .data_in        (grant),
        .data_out       (grant_previous)
    );

endmodule

